```
const PROCESSING_FEE_G = 5;
const quotePremium = (items) => {
  if (items.length === 0) return PROCESSING_FEE_G;
  const runeCount = items.length;
  const base = runeCount === 3 ? 60 : runeCount * 25;
  return Math.ceil((base * 11) / 10) + PROCESSING_FEE_G;
};
export const runScenario = (scenario) => {
